definition.script:
pipeline {
    agent any

    stages {

        stage('Checkout') {
            steps {
                echo 'Stage 1 — Code checked out'
            }
        }

        stage('Build Docker Image') {
            steps {
                echo 'Stage 2 — Building Docker image'
                sh 'docker --version'
                sh 'docker build -t ea-dre-nodeapp /var/jenkins_home/workspace/ea-dre-pipeline || echo "No Dockerfile yet"'
            }
        }

        stage('Test') {
            steps {
                echo 'Stage 3 — Running tests inside Docker'
                sh 'docker run --rm node:18-alpine node --version'
            }
        }

        stage('Deploy') {
            steps {
                echo 'Stage 4 — Deploying'
                echo 'Deployment complete!'
            }
        }
    }

    post {
        success {
            echo 'Pipeline succeeded!'
        }
        failure {
            echo 'Pipeline failed — check logs'
        }
    }
}
